  X[1] = 1; Y[1] = 2; Z[1] = 3;
  for (int i = 2; i <= n; i++) {
    X[i] = Y[i-1] + Z[i-2];
    Y[i] = 2 * X[i];
    Z[i] = 3 * X[i];
  }
  return X[n];
